package be.schaubroeck.lpb.rkm.rekenmotor.service.web;

import be.schaubroeck.lpb.tools.Admin;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Persoon;
import be.schaubroeck.lpb.tools.exception.MessageException;
import be.schaubroeck.lpb.tools.service.OpdrachtService;
import be.schaubroeck.lpb.tools.service.PersoonService;
import be.schaubroeck.lpb.tools.util.InitializeAdmin;
import be.schaubroeck.temporal.clock.TheClock;
import be.schaubroeck.temporal.interval.Day;
import be.schaubroeck.temporal.interval.Eternity;
import be.schaubroeck.temporal.interval.LocalDateInterval;
import be.schaubroeck.temporal.util.TemporalContext;
import org.springframework.beans.factory.annotation.Autowired;

public class StandaardPersoonOpdrachtWebService implements PersoonOpdrachtWebService {


    private static final String FETCH_OPDRACHT_ALL =
            "opdrachtSlices, weddeBepalingSlices{graad}, persoon{persoonSlices}, opperSlices{rszppo, weddeBerekening, boekhouding{opdrachtArtikelSet{opdrachtArtikels{artikel}}, hoofdArtikel{familie}}}";
    private static final String FETCH_OPDRACHT_MINIMUM = "opdrachtSlices, persoon{persoonSlices}, weddeBepalingSlices{graad}";

    @Autowired
    private PersoonService persoonService;
    @Autowired
    private OpdrachtService opdrachtService;

    @Override
    @InitializeAdmin
    public Opdracht getOpdracht(Admin admin, Integer personeelsNr, Integer opdrachtnr, LocalDateInterval periode) {
        boolean isPeriode = periode != null && periode.getStart() != null && periode.getEnd() != null;
        if (isPeriode) {
            TemporalContext.getInstance().setActualInterval(periode);
        } else {
            TemporalContext.getInstance().setActualInterval(new Eternity());
        }

        Persoon persoon = persoonService.getByPersoneelsNr(admin, personeelsNr);
        Opdracht opdracht =
                opdrachtService.getByPersoonOpdrachtNr(admin, persoon, opdrachtnr, isPeriode ? FETCH_OPDRACHT_ALL : FETCH_OPDRACHT_MINIMUM);
        TemporalContext.getInstance().clearActualInterval();

        return opdracht;
    }

    @Override
    @InitializeAdmin
    public Opdracht getOpdracht(Admin admin, Integer personeelsNr, Integer opdrachtnr) {

        Opdracht opdracht = this.getOpdracht(admin, personeelsNr, opdrachtnr, new Day(TheClock.getInstance().getToday()));

        if (opdracht == null) {
            TemporalContext.getInstance().setActualInterval(new Eternity());
            Persoon persoon = persoonService.getByPersoneelsNr(admin, personeelsNr);
            opdracht = opdrachtService.getByPersoonOpdrachtNr(admin, persoon, opdrachtnr, FETCH_OPDRACHT_ALL);
            TemporalContext.getInstance().clearActualInterval();

            if (opdracht == null) {
                throw new MessageException("Opdracht niet gevonden! p-nr = " + personeelsNr + ", o-nr = " + opdrachtnr);
            }
        }

        return opdracht;
    }
}
